import{_ as n,c as i,o as l,a1 as r}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Versionsprotokoll: Funktionsupdates | OpenSkills","description":"Sehen Sie sich den Versionsverlauf von OpenSkills an. Erfahren Sie mehr über den Update-Befehl, symbolische Links, private Repositories und andere neue Funktionen sowie wichtige Verbesserungen wie Pfad-Traversal-Schutz.","frontmatter":{"title":"Versionsprotokoll: Funktionsupdates | OpenSkills","sidebarTitle":"Neue Funktionen","subtitle":"Versionsprotokoll: Funktionsupdates | OpenSkills","description":"Sehen Sie sich den Versionsverlauf von OpenSkills an. Erfahren Sie mehr über den Update-Befehl, symbolische Links, private Repositories und andere neue Funktionen sowie wichtige Verbesserungen wie Pfad-Traversal-Schutz.","tags":["changelog","version history"],"order":1},"headers":[],"relativePath":"de/numman-ali/openskills/changelog/changelog/index.md","filePath":"de/numman-ali/openskills/changelog/changelog/index.md"}'),t={name:"de/numman-ali/openskills/changelog/changelog/index.md"};function a(s,e,o,u,d,h){return l(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="anderungsprotokoll" tabindex="-1">Änderungsprotokoll <a class="header-anchor" href="#anderungsprotokoll" aria-label="Permalink to &quot;Änderungsprotokoll&quot;">​</a></h1><p>Diese Seite dokumentiert den Versionsverlauf von OpenSkills und hilft Ihnen, die neuen Funktionen, Verbesserungen und Fehlerbehebungen jeder Version nachzuvollziehen.</p><hr><h2 id="_1-5-0-2026-01-17" tabindex="-1">[1.5.0] - 2026-01-17 <a class="header-anchor" href="#_1-5-0-2026-01-17" aria-label="Permalink to &quot;[1.5.0] - 2026-01-17&quot;">​</a></h2><h3 id="neue-funktionen" tabindex="-1">Neue Funktionen <a class="header-anchor" href="#neue-funktionen" aria-label="Permalink to &quot;Neue Funktionen&quot;">​</a></h3><ul><li><strong><code>openskills update</code></strong> - Aktualisiert installierte Skills aus ihren registrierten Quellen (Standard: alle aktualisieren)</li><li><strong>Quellen-Metadaten-Tracking</strong> - Installationsquellen werden jetzt erfasst, um zuverlässige Skill-Updates zu ermöglichen</li></ul><h3 id="verbesserungen" tabindex="-1">Verbesserungen <a class="header-anchor" href="#verbesserungen" aria-label="Permalink to &quot;Verbesserungen&quot;">​</a></h3><ul><li><strong>Mehrere Skills lesen</strong> - Der Befehl <code>openskills read</code> unterstützt jetzt kommagetrennte Skill-Namenlisten</li><li><strong>Nutzungshinweise generieren</strong> - Optimierte Hinweise für den Aufruf des read-Befehls in Shell-Umgebungen</li><li><strong>README</strong> - Update-Anleitung und Hinweise zur manuellen Nutzung hinzugefügt</li></ul><h3 id="fehlerbehebungen" tabindex="-1">Fehlerbehebungen <a class="header-anchor" href="#fehlerbehebungen" aria-label="Permalink to &quot;Fehlerbehebungen&quot;">​</a></h3><ul><li><strong>Update-Erlebnis optimiert</strong> - Skills ohne Quellen-Metadaten werden übersprungen und zur Neuinstallation aufgelistet</li></ul><hr><h2 id="_1-4-0-2026-01-17" tabindex="-1">[1.4.0] - 2026-01-17 <a class="header-anchor" href="#_1-4-0-2026-01-17" aria-label="Permalink to &quot;[1.4.0] - 2026-01-17&quot;">​</a></h2><h3 id="verbesserungen-1" tabindex="-1">Verbesserungen <a class="header-anchor" href="#verbesserungen-1" aria-label="Permalink to &quot;Verbesserungen&quot;">​</a></h3><ul><li><strong>README</strong> - Lokale Projektinstallation als Standard klarer kommuniziert, redundante sync-Hinweise entfernt</li><li><strong>Installationsmeldungen</strong> - Der Installer unterscheidet jetzt klar zwischen lokaler Projektinstallation und der Option <code>--global</code></li></ul><hr><h2 id="_1-3-2-2026-01-17" tabindex="-1">[1.3.2] - 2026-01-17 <a class="header-anchor" href="#_1-3-2-2026-01-17" aria-label="Permalink to &quot;[1.3.2] - 2026-01-17&quot;">​</a></h2><h3 id="verbesserungen-2" tabindex="-1">Verbesserungen <a class="header-anchor" href="#verbesserungen-2" aria-label="Permalink to &quot;Verbesserungen&quot;">​</a></h3><ul><li><strong>Dokumentation und AGENTS.md-Anleitung</strong> - Alle Befehlsbeispiele und generierten Nutzungshinweise verwenden einheitlich <code>npx openskills</code></li></ul><hr><h2 id="_1-3-1-2026-01-17" tabindex="-1">[1.3.1] - 2026-01-17 <a class="header-anchor" href="#_1-3-1-2026-01-17" aria-label="Permalink to &quot;[1.3.1] - 2026-01-17&quot;">​</a></h2><h3 id="fehlerbehebungen-1" tabindex="-1">Fehlerbehebungen <a class="header-anchor" href="#fehlerbehebungen-1" aria-label="Permalink to &quot;Fehlerbehebungen&quot;">​</a></h3><ul><li><strong>Windows-Installation</strong> - Pfadvalidierungsproblem auf Windows-Systemen behoben (&quot;Sicherheitsfehler: Installationspfad außerhalb des Zielverzeichnisses&quot;)</li><li><strong>CLI-Version</strong> - <code>npx openskills --version</code> liest jetzt korrekt die Versionsnummer aus der package.json</li><li><strong>SKILL.md im Root-Verzeichnis</strong> - Installationsproblem für Single-Skill-Repositories mit SKILL.md im Repository-Root behoben</li></ul><hr><h2 id="_1-3-0-2025-12-14" tabindex="-1">[1.3.0] - 2025-12-14 <a class="header-anchor" href="#_1-3-0-2025-12-14" aria-label="Permalink to &quot;[1.3.0] - 2025-12-14&quot;">​</a></h2><h3 id="neue-funktionen-1" tabindex="-1">Neue Funktionen <a class="header-anchor" href="#neue-funktionen-1" aria-label="Permalink to &quot;Neue Funktionen&quot;">​</a></h3><ul><li><p><strong>Symbolische Link-Unterstützung</strong> - Skills können jetzt über symbolische Links im Skill-Verzeichnis installiert werden (<a href="https://github.com/numman-ali/openskills/issues/3" target="_blank" rel="noreferrer">#3</a>)</p></li><li><p>Unterstützung für Git-basierte Skill-Updates durch Erstellen symbolischer Links aus geklonten Repositories</p></li><li><p>Unterstützung für lokale Skill-Entwicklungs-Workflows</p></li><li><p>Defekte symbolische Links werden elegant übersprungen</p></li><li><p><strong>Konfigurierbarer Ausgabepfad</strong> - Der sync-Befehl erhält neue Optionen <code>--output</code> / <code>-o</code> (<a href="https://github.com/numman-ali/openskills/issues/5" target="_blank" rel="noreferrer">#5</a>)</p></li><li><p>Synchronisation in beliebige <code>.md</code>-Dateien möglich (z.B. <code>.ruler/AGENTS.md</code>)</p></li><li><p>Automatische Dateierstellung mit Titel, falls die Datei nicht existiert</p></li><li><p>Automatische Erstellung verschachtelter Verzeichnisse bei Bedarf</p></li><li><p><strong>Installation aus lokalem Pfad</strong> - Unterstützung für die Installation aus lokalen Verzeichnissen (<a href="https://github.com/numman-ali/openskills/issues/10" target="_blank" rel="noreferrer">#10</a>)</p></li><li><p>Unterstützung für absolute Pfade (<code>/path/to/skill</code>)</p></li><li><p>Unterstützung für relative Pfade (<code>./skill</code>, <code>../skill</code>)</p></li><li><p>Unterstützung für Tilde-Expansion (<code>~/my-skills/skill</code>)</p></li><li><p><strong>Unterstützung für private Git-Repositories</strong> - Installation aus privaten Repositories möglich (<a href="https://github.com/numman-ali/openskills/issues/10" target="_blank" rel="noreferrer">#10</a>)</p></li><li><p>SSH-URLs (<code>git@github.com:org/private-skills.git</code>)</p></li><li><p>HTTPS-URLs mit Authentifizierung</p></li><li><p>Automatische Verwendung systemweiter SSH-Schlüssel</p></li><li><p><strong>Umfassende Testsuite</strong> - 88 Tests in 6 Testdateien</p></li><li><p>Unit-Tests für symbolische Link-Erkennung und YAML-Parsing</p></li><li><p>Integrationstests für install- und sync-Befehle</p></li><li><p>End-to-End-Tests für komplette CLI-Workflows</p></li></ul><h3 id="verbesserungen-3" tabindex="-1">Verbesserungen <a class="header-anchor" href="#verbesserungen-3" aria-label="Permalink to &quot;Verbesserungen&quot;">​</a></h3><ul><li><p><strong><code>--yes</code>-Flag überspringt jetzt alle Eingabeaufforderungen</strong> - Vollständiger Non-Interactive-Modus für CI/CD (<a href="https://github.com/numman-ali/openskills/issues/6" target="_blank" rel="noreferrer">#6</a>)</p></li><li><p>Keine Eingabeaufforderung beim Überschreiben bestehender Skills</p></li><li><p>Anzeige der Meldung <code>Overwriting: &lt;skill-name&gt;</code> beim Überspringen von Eingabeaufforderungen</p></li><li><p>Alle Befehle können jetzt in Headless-Umgebungen ausgeführt werden</p></li><li><p><strong>CI-Workflow neu angeordnet</strong> - Build-Schritt läuft jetzt vor den Tests</p></li><li><p>Stellt sicher, dass <code>dist/cli.js</code> für End-to-End-Tests existiert</p></li></ul><h3 id="sicherheit" tabindex="-1">Sicherheit <a class="header-anchor" href="#sicherheit" aria-label="Permalink to &quot;Sicherheit&quot;">​</a></h3><ul><li><strong>Pfad-Traversal-Schutz</strong> - Validierung, dass Installationspfade innerhalb des Zielverzeichnisses bleiben</li><li><strong>Symbolische Link-Dereferenzierung</strong> - <code>cpSync</code> verwendet <code>dereference: true</code> zum sicheren Kopieren symbolischer Link-Ziele</li><li><strong>Nicht-gieriger YAML-Regex</strong> - Verhindert potenzielle ReDoS-Angriffe beim Frontmatter-Parsing</li></ul><hr><h2 id="_1-2-1-2025-10-27" tabindex="-1">[1.2.1] - 2025-10-27 <a class="header-anchor" href="#_1-2-1-2025-10-27" aria-label="Permalink to &quot;[1.2.1] - 2025-10-27&quot;">​</a></h2><h3 id="fehlerbehebungen-2" tabindex="-1">Fehlerbehebungen <a class="header-anchor" href="#fehlerbehebungen-2" aria-label="Permalink to &quot;Fehlerbehebungen&quot;">​</a></h3><ul><li>README-Dokumentation bereinigt - Doppelte Abschnitte und falsche Flags entfernt</li></ul><hr><h2 id="_1-2-0-2025-10-27" tabindex="-1">[1.2.0] - 2025-10-27 <a class="header-anchor" href="#_1-2-0-2025-10-27" aria-label="Permalink to &quot;[1.2.0] - 2025-10-27&quot;">​</a></h2><h3 id="neue-funktionen-2" tabindex="-1">Neue Funktionen <a class="header-anchor" href="#neue-funktionen-2" aria-label="Permalink to &quot;Neue Funktionen&quot;">​</a></h3><ul><li><code>--universal</code>-Flag installiert Skills in <code>.agent/skills/</code> statt <code>.claude/skills/</code></li><li>Geeignet für Multi-Agent-Umgebungen (Claude Code + Cursor/Windsurf/Aider)</li><li>Vermeidet Konflikte mit nativen Claude Code Marketplace-Plugins</li></ul><h3 id="verbesserungen-4" tabindex="-1">Verbesserungen <a class="header-anchor" href="#verbesserungen-4" aria-label="Permalink to &quot;Verbesserungen&quot;">​</a></h3><ul><li>Lokale Projektinstallation ist jetzt die Standardoption (zuvor: globale Installation)</li><li>Skills werden standardmäßig in <code>./.claude/skills/</code> installiert</li></ul><hr><h2 id="_1-1-0-2025-10-27" tabindex="-1">[1.1.0] - 2025-10-27 <a class="header-anchor" href="#_1-1-0-2025-10-27" aria-label="Permalink to &quot;[1.1.0] - 2025-10-27&quot;">​</a></h2><h3 id="neue-funktionen-3" tabindex="-1">Neue Funktionen <a class="header-anchor" href="#neue-funktionen-3" aria-label="Permalink to &quot;Neue Funktionen&quot;">​</a></h3><ul><li>Umfassende einseitige README mit technischen Tiefeneinblicken</li><li>Direkter Vergleich mit Claude Code</li></ul><h3 id="fehlerbehebungen-3" tabindex="-1">Fehlerbehebungen <a class="header-anchor" href="#fehlerbehebungen-3" aria-label="Permalink to &quot;Fehlerbehebungen&quot;">​</a></h3><ul><li>Standort-Tag zeigt jetzt basierend auf dem Installationsort korrekt <code>project</code> oder <code>global</code> an</li></ul><hr><h2 id="_1-0-0-2025-10-26" tabindex="-1">[1.0.0] - 2025-10-26 <a class="header-anchor" href="#_1-0-0-2025-10-26" aria-label="Permalink to &quot;[1.0.0] - 2025-10-26&quot;">​</a></h2><h3 id="neue-funktionen-4" tabindex="-1">Neue Funktionen <a class="header-anchor" href="#neue-funktionen-4" aria-label="Permalink to &quot;Neue Funktionen&quot;">​</a></h3><ul><li>Erstveröffentlichung</li><li><code>npx openskills install &lt;source&gt;</code> - Installiert Skills aus GitHub-Repositories</li><li><code>npx openskills sync</code> - Generiert <code>&lt;available_skills&gt;</code>-XML für AGENTS.md</li><li><code>npx openskills list</code> - Zeigt installierte Skills an</li><li><code>npx openskills read &lt;name&gt;</code> - Lädt Skill-Inhalte für Agenten</li><li><code>npx openskills manage</code> - Interaktives Löschen von Skills</li><li><code>npx openskills remove &lt;name&gt;</code> - Löscht einen bestimmten Skill</li><li>Interaktive TUI-Oberfläche für alle Befehle</li><li>Unterstützung für Anthropics SKILL.md-Format</li><li>Progressive Disclosure (Skills bei Bedarf laden)</li><li>Unterstützung für gebündelte Ressourcen (references/, scripts/, assets/)</li></ul><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken zum Anzeigen der Quellcode-Positionen</strong></summary><blockquote><p>Aktualisiert: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th></tr></thead><tbody><tr><td>Original-Änderungsprotokoll</td><td><a href="https://github.com/numman-ali/openskills/blob/main/CHANGELOG.md" target="_blank" rel="noreferrer"><code>CHANGELOG.md</code></a></td></tr></tbody></table></details>',53)])])}const b=n(t,[["render",a]]);export{g as __pageData,b as default};
